const t={CHECKOUT:"Đặt hàng website",MANUAL_ORDER:"Đơn FB/IG/POS/Zalo",ORDER_CANCEL:"Hủy đơn — hoàn kho",ORDER_RETURN:"Hoàn đơn COD — cộng kho",ORDER_UNCANCEL:"Hoàn tác hủy — trừ kho",ORDER_EDIT_IN:"Sửa đơn — hoàn kho dòng cũ",ORDER_EDIT_OUT:"Sửa đơn — trừ kho dòng mới",MARKETING_GIFT:"Tặng KOL/KOC",MARKETING_GIFT_CANCEL:"Hủy tặng KOL — hoàn kho",MARKETING_GIFT_EDIT_IN:"Sửa marketing — hoàn kho dòng cũ",MARKETING_GIFT_EDIT_OUT:"Sửa marketing — trừ kho dòng mới",STOCK_RECEIPT:"Nhập kho / tăng tồn",ADMIN_ADJUSTMENT:"Admin chỉnh tồn kho",RETURN:"Hoàn hàng thủ công",REFUND:"Hoàn tiền / trả đơn"};function T(n){const e=n.referenceLabel||n.referenceId;return e?n.referenceType==="marketing_gift"||String(e).startsWith("MK")?`Marketing · ${e}`:n.referenceType==="order"||String(e).startsWith("DH")?`Đơn hàng · ${e}`:n.referenceType==="manual_return"?`Hoàn thủ công · ${e}`:e:"—"}function E(n){return n==="ORDER_EDIT_IN"||n==="ORDER_EDIT_OUT"||n==="MARKETING_GIFT_EDIT_IN"||n==="MARKETING_GIFT_EDIT_OUT"}const _=[{value:"all",label:"Tất cả nguyên nhân"},...Object.entries(t).map(([n,e])=>({value:n,label:e}))];export{t as S,_ as a,T as f,E as i};
